async (params, browser) => {
  // Open Trello
  await browser.open('https://trello.com')

  // Let Trello load
  await browser.wait(3000)

  // Fetch boards via Trello REST API
  const result = await browser.evaluate(`const resp = await fetch('/1/members/me/boards?fields=name,url,shortUrl,closed,idOrganization,dateLastActivity', { credentials: 'same-origin' }); if (!resp.ok) throw new Error('Trello API error: ' + resp.status); const boards = await resp.json(); const active = boards.filter(b => !b.closed).map(b => ({ name: b.name, url: b.url || b.shortUrl, last_activity: b.dateLastActivity, org_id: b.idOrganization || '' })); return { result_count: active.length, boards: active }`)

  return result
}
